43	// Maps any pipeline-related identifier (skill, agent, or slash-command name)
44	// to a pipeline phase. The agent may invoke a phase's work via the Skill tool,
45	// the Agent/Task tool, or by reading a skill's SKILL.md directly — detection
46	// needs to cover all three paths.
47	const NAME_TO_PHASE: Record<string, "analyze" | "align" | "build"> = {
48	  // Skills
49	  "assignment-analysis": "analyze",
50	  "career-alignment": "align",
51	  "proposal-builder": "build",
52	  // Agents
53	  "assignment-analyzer": "analyze",
54	  "career-matcher": "align",
55	  "proposal-writer": "build",
56	  // Slash commands
57	  "analyze-assignment": "analyze",
58	  "align-career": "align",
59	  "build-proposal": "build",
60	};
61	
62	// Plugin-qualified identifiers arrive as "<plugin>:<name>" (e.g.
63	// "assignment-ally:assignment-analysis"). Strip the prefix so lookups match
64	// the bare skill/agent name.
65	function stripPluginPrefix(id: string | undefined): string | undefined {
66	  if (!id) return id;
67	  const i = id.lastIndexOf(":");
68	  return i >= 0 ? id.slice(i + 1) : id;
69	}
70	
71	// Human-friendly status label for the loading indicator, derived from the
72	// current tool_use block. Returned string is shown verbatim next to the
73	// spinner so the user can see what the agent is actually doing.
74	function describeToolUse(block: {
75	  name?: string;
76	  input?: Record<string, unknown>;
77	}): string | undefined {
78	  const name = block.name;
79	  const input = block.input ?? {};
80	
81	  if (name === "Skill") {
82	    const skill = stripPluginPrefix(input.skill as string | undefined);
83	    if (skill === "assignment-analysis") return "Analyzing your material...";
84	    if (skill === "career-alignment") return "Aligning with career goals...";
85	    if (skill === "proposal-builder") return "Building proposal...";
86	    // Internal skills — do not announce to the user.
87	    if (skill === "pipeline-gate") return undefined;
88	    return "Working on it...";
89	  }
90	
91	  if (name === "Agent" || name === "Task") {
92	    const agent = stripPluginPrefix(
93	      (input.subagent_type ?? input.agent_type) as string | undefined
94	    );
95	    if (agent === "assignment-analyzer") return "Analyzing your material...";
96	    if (agent === "career-matcher") return "Matching career opportunities...";
97	    if (agent === "proposal-writer") return "Writing proposal...";
98	    return agent ? `Delegating to ${agent}...` : "Delegating work...";
99	  }
100	
101	  if (name === "Read") {
102	    const p = (input.file_path ?? "") as string;
103	    if (/\/skills\/.*\/SKILL\.md$/i.test(p)) return "Getting started...";
104	    if (/\/skills\//i.test(p)) return "Reviewing reference material...";
105	    if (/\/syllabi\//i.test(p)) return "Reading syllabus...";
106	    if (/\/industry\//i.test(p)) return "Reading industry data...";
107	    if (/\/users\//i.test(p)) return "Reading student profile...";
108	    if (/\/examples\//i.test(p)) return "Reading example...";
109	    return "Reading document...";
110	  }
111	
112	  if (name === "Grep") return "Searching content...";
113	  if (name === "Glob") return "Finding files...";
114	  if (name === "AskUserQuestion") return "Preparing a question...";
115	  if (name === "TodoWrite") return "Planning next steps...";
116	  if (name === "Write") return "Saving output...";
117	
118	  return undefined;
119	}
