121	function detectPhaseFromBlock(block: {
122	  type: string;
123	  name?: string;
124	  input?: Record<string, unknown>;
125	}): "analyze" | "align" | "build" | undefined {
126	  if (block.type !== "tool_use") return undefined;
127	  const input = block.input ?? {};
128	
129	  // 1) Skill tool — { skill: "<name>", ... }
130	  if (block.name === "Skill") {
131	    const skill = stripPluginPrefix(input.skill as string | undefined);
132	    if (skill && NAME_TO_PHASE[skill]) return NAME_TO_PHASE[skill];
133	  }
134	
135	  // 2) Agent/Task tool — { subagent_type: "<name>", ... }
136	  if (block.name === "Agent" || block.name === "Task") {
137	    const agent = stripPluginPrefix(
138	      (input.subagent_type ?? input.agent_type) as string | undefined
139	    );
140	    if (agent && NAME_TO_PHASE[agent]) return NAME_TO_PHASE[agent];
141	  }
142	
143	  // 3) Read tool opening a skill's SKILL.md — strong signal that the agent
144	  //    is actually executing that phase even if no Skill/Agent tool was used.
145	  if (block.name === "Read") {
146	    const p = (input.file_path ?? "") as string;
147	    const m = p.match(/\/skills\/([^/]+)\/SKILL\.md$/i);
148	    if (m && NAME_TO_PHASE[m[1]]) return NAME_TO_PHASE[m[1]];
149	  }
150	
151	  // 4) Fallback — scan the stringified input for any mapped identifier. Catches
152	  //    cases like Bash/Glob reading skill directories, or tools we don't know
153	  //    about whose input happens to name a skill/agent/command.
154	  try {
155	    const inputStr = JSON.stringify(input);
156	    for (const [name, phase] of Object.entries(NAME_TO_PHASE)) {
157	      if (inputStr.includes(name)) return phase;
158	    }
159	  } catch {
160	    // ignore — stringify can fail on circular refs
161	  }
162	
163	  return undefined;
164	}
