225	
226	function parseExampleMetadata(
227	  markdown: string
228	): { title: string; scenario: string } {
229	  const titleMatch = markdown.match(/^#\s+(.+)$/m);
230	  // Strip the "P1: " prefix used internally so the card title reads naturally.
231	  const title = titleMatch
232	    ? titleMatch[1].replace(/^P\d+:\s*/, "").trim()
233	    : "";
234	
235	  // First paragraph under the "## Scenario" heading, up to the next blank
236	  // line or heading. Falls back to empty string if the section is missing.
237	  const scenarioMatch = markdown.match(
238	    /^##\s+Scenario\s*\n+([^\n][\s\S]*?)(?:\n\s*\n|\n##\s)/m
239	  );
240	  const scenario = scenarioMatch ? scenarioMatch[1].trim() : "";
241	
242	  return { title, scenario };
243	}
244	
245	type ExampleTurn =
246	  | { role: "user"; content: string }
247	  | { role: "assistant"; content: string };
248	
249	// Extract just the chat transcript the student would actually see in a live
250	// session: user messages and the agent's user-facing responses. Drops the
251	// meta sections (Scenario, Data Sources Used, Why This Interaction Succeeds)
252	// and the "Agent Internal Reasoning" blocks, which are authoring notes, not
253	// part of the real interaction.
254	function parseExampleTurns(markdown: string): ExampleTurn[] {
255	  // Isolate the conversation section. If "Why This Interaction Succeeds"
256	  // exists, use it as a hard right boundary.
257	  const convoStart = markdown.search(/^##\s+Conversation\s*$/m);
258	  if (convoStart < 0) return [];
259	  let convo = markdown.slice(convoStart).replace(/^##\s+Conversation\s*\n+/, "");
260	  const whyIdx = convo.search(/^##\s+Why This Interaction Succeeds\s*$/m);
261	  if (whyIdx >= 0) convo = convo.slice(0, whyIdx);
262	
263	  // Drop every "Agent Internal Reasoning" block. It ends at the next known
264	  // marker — either "Agent Response" or the next "Turn N —" header.
265	  convo = convo.replace(
266	    /\*\*Agent Internal Reasoning:\*\*[\s\S]*?(?=\*\*Agent Response:\*\*|\*\*Turn \d+ — )/g,
267	    ""
268	  );
269	
270	  // Walk remaining markers in order: each becomes a turn. Everything between
271	  // one marker and the next is that turn's content.
272	  const markerRe =
273	    /\*\*(?:Turn \d+ — [^:*]+:|Agent Response:)\*\*/g;
274	  const matches: Array<{ kind: "user" | "assistant"; end: number; start: number }> =
275	    [];
276	  for (const m of convo.matchAll(markerRe)) {
277	    const kind = m[0].startsWith("**Agent Response") ? "assistant" : "user";
278	    matches.push({ kind, start: m.index!, end: m.index! + m[0].length });
279	  }
280	
281	  const turns: ExampleTurn[] = [];
282	  for (let i = 0; i < matches.length; i++) {
283	    const m = matches[i];
284	    const contentStart = m.end;
285	    const contentEnd = i + 1 < matches.length ? matches[i + 1].start : convo.length;
286	    let content = convo.slice(contentStart, contentEnd).trim();
287	
288	    // Strip the "---" turn separator that often precedes the next Turn header,
289	    // plus leading/trailing horizontal rules that were only there as visual
290	    // dividers between Turn N and Turn N+1 in the source file.
291	    content = content.replace(/\n?\s*---+\s*$/, "").trim();
292	    content = content.replace(/^---+\s*\n?/, "").trim();
293	
294	    // Unwrap surrounding quotation marks: the source files stylize every
295	    // user turn and most agent responses as "..." but a real chat bubble
296	    // doesn't show quotes around itself.
297	    content = stripWrappingQuotes(content);
298	
299	    if (content) turns.push({ role: m.kind, content });
300	  }
301	
302	  return turns;
303	}
304	
305	function stripWrappingQuotes(text: string): string {
306	  // Only unwrap when the whole turn is one quoted block — don't touch
307	  // inline quotes inside the content.
308	  const trimmed = text.trim();
309	  if (
310	    (trimmed.startsWith('"') && trimmed.endsWith('"')) ||
311	    (trimmed.startsWith("“") && trimmed.endsWith("”"))
312	  ) {
313	    const inner = trimmed.slice(1, -1);
314	    // Guard: if the inner text also contains unescaped quote pairs that would
315	    // indicate this isn't a single wrapping quote, keep it as-is.
316	    if (!inner.includes('"\n') && !inner.includes('\n"')) {
317	      return inner.trim();
318	    }
319	  }
320	  return trimmed;
321	}
