450	// ── Chat endpoint — streams agent responses via SSE ──────────────────
451	
452	app.post("/api/chat", async (req: Request, res: Response) => {
453	  const { sessionId, message, fileText } = req.body as {
454	    sessionId: string;
455	    message: string;
456	    fileText?: string;
457	  };
458	
459	  const session = sessions.get(sessionId);
