469	
470	  // pipeline-gate is an internal, agent-only skill — reject direct user calls.
471	  if (/^\s*\/\s*pipeline-gate\b/i.test(message)) {
472	    res
473	      .status(400)
474	      .json({ error: "pipeline-gate is an internal skill and cannot be invoked directly." });
475	    return;
476	  }
477	
478	  // ── Pipeline enforcement ──────────────────────────────────────────
479	  // Only enforce on known button prompts; free-text always passes through
480	  const stepForPrompt = identifyPipelineStep(message);
481	
482	  if (stepForPrompt === "align" && stepIndex(session.pipelineStep) < 1) {
483	    res
484	      .status(400)
485	      .json({ error: "Please analyze an assignment first.", pipelineStep: session.pipelineStep });
486	    return;
487	  }
488	  if (stepForPrompt === "build" && stepIndex(session.pipelineStep) < 2) {
489	    res.status(400).json({
490	      error:
491	        stepIndex(session.pipelineStep) < 1
492	          ? "Please analyze an assignment and align career goals first."
493	          : "Please complete career alignment first.",
494	      pipelineStep: session.pipelineStep,
495	    });
496	    return;
497	  }
498	
499	  // SSE headers
500	  res.setHeader("Content-Type", "text/event-stream");
501	  res.setHeader("Cache-Control", "no-cache");
502	  res.setHeader("Connection", "keep-alive");
503	  res.flushHeaders();
504	
505	  // Build the prompt
506	  let prompt = message;
507	
508	  // Prepend uploaded file text if provided
509	  if (fileText) {
510	    prompt = `[Uploaded assignment/syllabus document]\n${fileText}\n\n[Student's message]\n${message}`;
511	  }
512	
513	  // On first message, include student context
514	  if (!session.sdkSessionId) {
515	    const s = session.student;
516	    prompt =
517	      `[Student context — use this to personalize your responses]\n` +
518	      `Name: ${s.name}\n` +
519	      `Major: ${s.major}\n` +
520	      `Year: ${s.year}\n` +
521	      `Career goals: ${s.careerGoals}\n` +
522	      `Course they want to work on: ${s.course}\n\n` +
523	      prompt;
524	  }
525	
526	  try {
527	    const options = buildOptions({
528	      maxTurns: 50,
529	      ...(session.sdkSessionId ? { resume: session.sdkSessionId } : {}),
530	    });
531	
532	    const conversation = query({ prompt, options });
533	    let accumulatedText = "";
534	    // Tracks the latest phase the agent touched in this turn. We only mark
535	    // that phase complete if (a) the agent later moves to a strictly-later
536	    // phase or (b) the turn ends without a pending question to the user.
537	    let phaseInTurn: "analyze" | "align" | "build" | undefined;
538	
539	    for await (const msg of conversation) {
540	      if (msg.type === "assistant") {
541	        const content = (msg as Record<string, unknown>).message as
542	          | {
543	              content?: Array<{
544	                type: string;
545	                text?: string;
546	                name?: string;
547	                input?: Record<string, unknown>;
548	              }>;
549	            }
550	          | undefined;
551	        if (content?.content) {
552	          for (const block of content.content) {
553	            if (block.type === "text" && block.text) {
554	              accumulatedText += block.text;
555	              res.write(
556	                `data: ${JSON.stringify({ type: "text", content: block.text })}\n\n`
557	              );
558	            } else if (block.type === "tool_use") {
559	              const statusMsg = describeToolUse(block);
560	              if (statusMsg) {
561	                res.write(
562	                  `data: ${JSON.stringify({
563	                    type: "status",
564	                    content: statusMsg,
565	                  })}\n\n`
566	                );
567	              }
568	              const phase = detectPhaseFromBlock(block);
569	              if (phase) {
570	                // Starting a strictly-later phase implies the previous phase
571	                // is complete — advance pipelineStep for it now.
572	                if (
573	                  phaseInTurn &&
574	                  PHASE_ORDER[phase] > PHASE_ORDER[phaseInTurn]
575	                ) {
576	                  advancePipeline(session, phaseInTurn);
577	                }
578	                phaseInTurn = phase;
579	                res.write(
580	                  `data: ${JSON.stringify({
581	                    type: "phase",
582	                    activePhase: phase,
583	                    pipelineStep: session.pipelineStep,
584	                  })}\n\n`
585	                );
586	              }
587	            }
588	          }
589	        }
590	      }
591	
592	      if (msg.type === "result") {
593	        const result = msg as Record<string, unknown>;
594	        const sdkSessionId = result.session_id as string | undefined;
595	        if (sdkSessionId) {
596	          session.sdkSessionId = sdkSessionId;
597	        }
598	
599	        // Extract goal profile from agent response if present
600	        const profileJson = extractGoalProfile(accumulatedText);
601	        if (profileJson) {
602	          session.goalProfile = profileJson;
603	        }
604	
605	        // Prefer the pipeline-gate skill's explicit verdict over the
606	        // trailing-question heuristic. The gate is the agent's own judgment
607	        // about whether its phase work is actually done for this turn.
608	        const gate = extractPipelineGate(accumulatedText);
609	        if (gate) {
610	          if (gate.canAdvance) {
611	            advancePipeline(session, gate.phase);
612	            session.awaitingInfo = null;
613	          } else {
614	            session.awaitingInfo = gate.phase;
615	          }
616	        } else if (phaseInTurn && !endsWithQuestion(accumulatedText)) {
617	          // Fallback only when the agent forgot to call pipeline-gate.
618	          advancePipeline(session, phaseInTurn);
619	          session.awaitingInfo = null;
620	        }
621	        // No gate + question-ending: leave session.awaitingInfo as-is so a
622	        // tangential turn doesn't erase the halfway marker.
623	
624	        const success = result.subtype === "success";
625	
626	        res.write(
627	          `data: ${JSON.stringify({
628	            type: "done",
629	            sessionId: sdkSessionId,
630	            success,
631	            pipelineStep: session.pipelineStep,
632	            awaitingInfo: session.awaitingInfo ?? null,
633	            hasGoalProfile: !!session.goalProfile,
634	          })}\n\n`
635	        );
636	      }
637	    }
638	  } catch (err) {
639	    const errorMsg =
640	      err instanceof Error ? err.message : "An unexpected error occurred.";
641	    res.write(
642	      `data: ${JSON.stringify({ type: "error", content: errorMsg })}\n\n`
643	    );
644	  }
645	
646	  res.end();
647	});
648	
649	// ── Pipeline helpers ─────────────────────────────────────────────────
650	
651	const STEP_ORDER: PipelineStep[] = [
652	  "ready",
653	  "analyzed",
654	  "aligned",
655	  "proposed",
656	];
657	
658	function stepIndex(step: PipelineStep): number {
659	  return STEP_ORDER.indexOf(step);
660	}
661	
662	function identifyPipelineStep(
663	  message: string
664	): "analyze" | "align" | "build" | null {
665	  if (message === PIPELINE_PROMPTS.analyze) return "analyze";
666	  if (message === PIPELINE_PROMPTS.align) return "align";
667	  if (message === PIPELINE_PROMPTS.build) return "build";
668	  return null;
669	}
670	
671	function advancePipeline(
672	  session: ChatSession,
673	  step: "analyze" | "align" | "build"
674	): void {
675	  const nextStep: Record<string, PipelineStep> = {
676	    analyze: "analyzed",
677	    align: "aligned",
678	    build: "proposed",
679	  };
680	  const target = nextStep[step];
681	  // Only advance forward, never go backward
682	  if (stepIndex(target) > stepIndex(session.pipelineStep)) {
683	    session.pipelineStep = target;
684	  }
685	}
686	
687	const PHASE_ORDER: Record<"analyze" | "align" | "build", number> = {
688	  analyze: 1,
689	  align: 2,
690	  build: 3,
691	};
692	
693	// Heuristic: the agent is waiting on the user when its final prose ends with
694	// a question. In that case the phase it started isn't actually finished — the
695	// user still needs to answer before the step should be marked complete.
696	// Used only as a fallback when the pipeline-gate skill wasn't invoked.
697	function endsWithQuestion(text: string): boolean {
698	  const cleaned = text
699	    // Strip internal markers so the real prose is what we test.
700	    .replace(
701	      /<!-- GOAL_PROFILE_JSON -->[\s\S]*?<!-- \/GOAL_PROFILE_JSON -->/g,
702	      ""
703	    )
704	    .replace(/<!-- PIPELINE_GATE[\s\S]*?-->/g, "")
705	    // Strip trailing whitespace and markdown punctuation (e.g. "?**", "?*_").
706	    .replace(/[\s*_`~]+$/, "");
707	  return cleaned.endsWith("?");
708	}
709	
710	// The pipeline-gate skill emits a single-line JSON payload inside an HTML
711	// comment, e.g.:
712	//   <!-- PIPELINE_GATE {"phase":"analyze","canAdvance":true,...} -->
713	// (leading/trailing whitespace and newlines inside the comment are allowed).
714	// Multiple gates in one turn are tolerated — we use the last one.
715	const PIPELINE_GATE_RE = /<!-- PIPELINE_GATE\s*([\s\S]*?)\s*-->/g;
716	
717	function extractPipelineGate(
718	  text: string
719	):
720	  | { phase: "analyze" | "align" | "build"; canAdvance: boolean; reason?: string }
721	  | null {
722	  const matches = [...text.matchAll(PIPELINE_GATE_RE)];
723	  if (matches.length === 0) return null;
724	  const last = matches[matches.length - 1];
725	  try {
726	    const parsed = JSON.parse(last[1]) as {
727	      phase?: unknown;
728	      canAdvance?: unknown;
729	      reason?: unknown;
730	    };
731	    if (
732	      parsed.phase !== "analyze" &&
733	      parsed.phase !== "align" &&
734	      parsed.phase !== "build"
735	    ) {
736	      return null;
737	    }
738	    if (typeof parsed.canAdvance !== "boolean") return null;
739	    return {
740	      phase: parsed.phase,
741	      canAdvance: parsed.canAdvance,
742	      reason: typeof parsed.reason === "string" ? parsed.reason : undefined,
743	    };
744	  } catch {
745	    return null;
746	  }
747	}
748	
749	// ── Goal profile extraction ─────────────────────────────────────────
750	
751	const PROFILE_MARKER_RE =
752	  /<!-- GOAL_PROFILE_JSON -->\s*```(?:json)?\s*([\s\S]*?)\s*```\s*<!-- \/GOAL_PROFILE_JSON -->/;
753	
754	function extractGoalProfile(text: string): StudentGoalProfile | null {
755	  const match = text.match(PROFILE_MARKER_RE);
756	  if (!match) return null;
757	  try {
758	    const parsed = JSON.parse(match[1]);
759	    // Validate minimum required fields
760	    if (!parsed.careerGoals?.primary) return null;
761	    // Ensure required arrays exist
762	    if (!Array.isArray(parsed.sectionsOffered)) parsed.sectionsOffered = [];
763	    if (!Array.isArray(parsed.sectionsCompleted)) parsed.sectionsCompleted = [];
764	    return parsed as StudentGoalProfile;
765	  } catch {
766	    return null;
767	  }
768	}
769	
770	function sessionExportToMarkdown(
771	  student: StudentProfile,
772	  profile: StudentGoalProfile | undefined,
773	  exportedAt: string
774	): string {
775	  const lines: string[] = [];
776	
777	  lines.push(`# Profile: ${student.name}`);
778	  lines.push("");
779	
780	  // Student Profile (always present)
781	  lines.push("## Student Profile");
782	  lines.push("");
783	  lines.push(`**Major:** ${student.major}`);
784	  lines.push(`**Year:** ${student.year}`);
785	  lines.push(`**Course:** ${student.course}`);
786	  lines.push(`**Career goals:** ${student.careerGoals}`);
787	  lines.push("");
788	
789	  // Goal profile sections (only if present)
790	  if (profile) {
791	    lines.push(`**Goal profile created:** ${profile.createdAt}`);
792	    lines.push("");
793	
794	    lines.push("## Career Goals");
795	    lines.push("");
796	    lines.push(`**Primary goal:** ${profile.careerGoals.primary}`);
797	    if (profile.careerGoals.secondary) {
798	      lines.push(`**Secondary goal:** ${profile.careerGoals.secondary}`);
799	    }
800	    if (profile.careerGoals.targetEmployers?.length) {
801	      lines.push(
802	        `**Target employers:** ${profile.careerGoals.targetEmployers.join(", ")}`
803	      );
804	    }
805	    if (profile.careerGoals.industryPreference) {
806	      lines.push(
807	        `**Industry preference:** ${profile.careerGoals.industryPreference}`
808	      );
809	    }
810	    if (profile.careerGoals.timeline) {
811	      lines.push(`**Timeline:** ${profile.careerGoals.timeline}`);
812	    }
813	    lines.push("");
814	
815	    if (profile.motivations) {
816	      lines.push("## Motivations");
817	      lines.push("");
818	      if (profile.motivations.whatExcitesYou) {
819	        lines.push(
820	          `**What excites you:** ${profile.motivations.whatExcitesYou}`
821	        );
822	      }
823	      if (profile.motivations.whyThisPath) {
824	        lines.push(`**Why this path:** ${profile.motivations.whyThisPath}`);
825	      }
826	      if (profile.motivations.problemsToSolve) {
827	        lines.push(
828	          `**Problems to solve:** ${profile.motivations.problemsToSolve}`
829	        );
830	      }
831	      lines.push("");
832	    }
833	
834	    if (profile.personalContext) {
835	      lines.push("## Personal Context");
836	      lines.push("");
837	      if (profile.personalContext.workStatus) {
838	        lines.push(`**Work status:** ${profile.personalContext.workStatus}`);
839	      }
840	      if (profile.personalContext.relevantExperience) {
841	        lines.push(
842	          `**Relevant experience:** ${profile.personalContext.relevantExperience}`
843	        );
844	      }
845	      if (profile.personalContext.constraints) {
846	        lines.push(`**Constraints:** ${profile.personalContext.constraints}`);
847	      }
848	      if (profile.personalContext.perspective) {
849	        lines.push(`**Perspective:** ${profile.personalContext.perspective}`);
850	      }
851	      lines.push("");
852	    }
853	
854	    if (
855	      profile.skillsSelfAssessment &&
856	      Object.keys(profile.skillsSelfAssessment).length > 0
857	    ) {
858	      lines.push("## Skills Self-Assessment");
859	      lines.push("");
860	      lines.push("| Skill | Level |");
861	      lines.push("|-------|-------|");
862	      for (const [skill, level] of Object.entries(
863	        profile.skillsSelfAssessment
864	      )) {
865	        const label = skill.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase());
866	        lines.push(`| ${label} | ${level} |`);
867	      }
868	      lines.push("");
869	    }
870	  }
871	
872	  lines.push("---");
873	  lines.push(`*Generated by AssignmentAlly on ${exportedAt}*`);
874	  lines.push("");
875	  lines.push(
876	    "*Upload the JSON version of this file on the start page to resume without re-taking the survey.*"
877	  );
878	
879	  return lines.join("\n");
880	}
881	
882	// ── Profile download endpoint ───────────────────────────────────────
883	// Returns the combined session export: the intro-survey StudentProfile
884	// (always) plus the richer StudentGoalProfile (when one has been built).
885	
886	app.get(
887	  "/api/session/:sessionId/profile",
888	  (req: Request, res: Response) => {
889	    const sid = String(req.params.sessionId);
890	    const session = sessions.get(sid);
891	    if (!session) {
892	      res.status(404).json({ error: "Session not found." });
893	      return;
894	    }
895	
896	    const format = String(req.query.format ?? "json");
897	    const safeName = session.student.name.replace(/[^a-zA-Z0-9-_ ]/g, "").replace(/\s+/g, "-");
898	    const exportedAt = new Date().toISOString();
899	
900	    if (format === "markdown") {
901	      const md = sessionExportToMarkdown(
902	        session.student,
903	        session.goalProfile,
904	        exportedAt
905	      );
906	      res.setHeader("Content-Type", "text/markdown; charset=utf-8");
907	      res.setHeader(
908	        "Content-Disposition",
909	        `attachment; filename="${safeName}-profile.md"`
910	      );
911	      res.send(md);
912	    } else {
913	      const payload: SessionExport = {
914	        version: 1,
915	        exportedAt,
916	        student: session.student,
917	        ...(session.goalProfile ? { goalProfile: session.goalProfile } : {}),
918	      };
919	      res.setHeader("Content-Type", "application/json; charset=utf-8");
920	      res.setHeader(
921	        "Content-Disposition",
922	        `attachment; filename="${safeName}-profile.json"`
923	      );
924	      res.json(payload);
925	    }
926	  }
927	);
928	
929	app.listen(PORT, () => {
930	  console.log(`AssignmentAlly running at http://localhost:${PORT}`);
931	});
