42	function inferPhaseFromInput(message, fileText) {
43	  if (fileText) return "analyze";
44	
45	  const analyzeBtn = quickActions.querySelector('[data-step="analyze"]');
46	  const alignBtn = quickActions.querySelector('[data-step="align"]');
47	  const buildBtn = quickActions.querySelector('[data-step="build"]');
48	  if (message === analyzeBtn.dataset.prompt) return "analyze";
49	  if (message === alignBtn.dataset.prompt) return "align";
50	  if (message === buildBtn.dataset.prompt) return "build";
51	
52	  const idx = stepIndex(pipelineStep);
53	  if (idx === 0) return "analyze";
54	  if (idx === 1) return "align";
55	  if (idx === 2) return "build";
56	  return null;
57	}
