59	function updateButtonStates() {
60	  const analyzeBtn = quickActions.querySelector('[data-step="analyze"]');
61	  const alignBtn = quickActions.querySelector('[data-step="align"]');
62	  const buildBtn = quickActions.querySelector('[data-step="build"]');
63	  const connector1 = document.getElementById("connector-1");
64	  const connector2 = document.getElementById("connector-2");
65	  const idx = stepIndex(pipelineStep);
66	
67	  // Reset all
68	  [analyzeBtn, alignBtn, buildBtn].forEach((btn) => {
69	    btn.classList.remove(
70	      "action-chip--completed",
71	      "action-chip--current",
72	      "action-chip--locked",
73	      "action-chip--working"
74	    );
75	    btn.disabled = false;
76	    btn.title = "";
77	  });
78	  connector1.classList.remove(
79	    "step-connector--completed",
80	    "step-connector--partial"
81	  );
82	  connector2.classList.remove(
83	    "step-connector--completed",
84	    "step-connector--partial"
85	  );
86	
87	  // Analyze button
88	  if (idx >= 1) {
89	    analyzeBtn.classList.add("action-chip--completed");
90	    analyzeBtn.disabled = true;
91	    analyzeBtn.title = "Assignment analysis complete";
92	    analyzeBtn.querySelector(".step-indicator").textContent = "\u2713";
93	  } else {
94	    analyzeBtn.classList.add("action-chip--current");
95	    analyzeBtn.querySelector(".step-indicator").textContent = "1";
96	  }
97	
98	  // Connector 1
99	  if (idx >= 1) {
100	    connector1.classList.add("step-connector--completed");
101	  }
102	
103	  // Align button
104	  if (idx >= 2) {
105	    alignBtn.classList.add("action-chip--completed");
106	    alignBtn.disabled = true;
107	    alignBtn.title = "Career alignment complete";
108	    alignBtn.querySelector(".step-indicator").textContent = "\u2713";
109	  } else if (idx >= 1) {
110	    alignBtn.classList.add("action-chip--current");
111	    alignBtn.querySelector(".step-indicator").textContent = "2";
112	  } else {
113	    alignBtn.classList.add("action-chip--locked");
114	    alignBtn.disabled = true;
115	    alignBtn.title = "Complete assignment analysis first";
116	    alignBtn.querySelector(".step-indicator").textContent = "2";
117	  }
118	
119	  // Connector 2
120	  if (idx >= 2) {
121	    connector2.classList.add("step-connector--completed");
122	  }
123	
124	  // Awaiting-info halfway marker — only paints on the connector AFTER the
125	  // phase-in-progress chip, and never replaces an already-completed connector.
126	  if (awaitingInfo === "analyze" && idx < 1) {
127	    connector1.classList.add("step-connector--partial");
128	  } else if (awaitingInfo === "align" && idx < 2) {
129	    connector2.classList.add("step-connector--partial");
130	  }
131	  // awaitingInfo === "build": no connector after chip 3, so the chip stays
132	  // --current. (Visible build-awaiting UX is deliberately out of scope.)
133	
134	  // Build button
135	  if (idx >= 3) {
136	    buildBtn.classList.add("action-chip--completed");
137	    buildBtn.disabled = true;
138	    buildBtn.title = "Proposal built";
139	    buildBtn.querySelector(".step-indicator").textContent = "\u2713";
140	  } else if (idx >= 2) {
141	    buildBtn.classList.add("action-chip--current");
142	    buildBtn.querySelector(".step-indicator").textContent = "3";
143	  } else {
144	    buildBtn.classList.add("action-chip--locked");
145	    buildBtn.disabled = true;
146	    buildBtn.title =
147	      idx < 1
148	        ? "Complete analysis and alignment first"
149	        : "Complete career alignment first";
150	    buildBtn.querySelector(".step-indicator").textContent = "3";
151	  }
152	
153	  // Working overlay — active phase pulses with a spinner in its step indicator.
154	  // Takes visual priority over completed/current/locked via CSS source order.
155	  if (activePhase) {
156	    const activeBtn = quickActions.querySelector(
157	      `[data-step="${activePhase}"]`
158	    );
159	    if (activeBtn) {
160	      activeBtn.classList.add("action-chip--working");
161	      const indicator = activeBtn.querySelector(".step-indicator");
162	      indicator.textContent = "";
163	      const spinner = document.createElement("span");
164	      spinner.className = "chip-spinner";
165	      spinner.setAttribute("aria-hidden", "true");
166	      indicator.appendChild(spinner);
167	    }
168	  }
169	
170	  // Preserve streaming-lock: chips stay disabled until the turn ends.
171	  if (isStreaming) {
172	    [analyzeBtn, alignBtn, buildBtn].forEach((btn) => (btn.disabled = true));
173	  }
174	}
