638	async function sendMessage() {
639	  const text = chatInput.value.trim();
640	  if (!text || isStreaming || !sessionId) return;
641	
642	  // Capture and clear pending file info
643	  const fileText = pendingFileText;
644	  const fileName = pendingFileName;
645	  pendingFileText = null;
646	  pendingFileName = null;
647	
648	  // Add user message — include file name if uploaded
649	  const displayText = fileName ? `[Uploaded: ${fileName}]\n${text}` : text;
650	  appendMessage("user", displayText);
651	  chatInput.value = "";
652	  chatInput.style.height = "auto";
653	
654	  // Optimistically highlight the chip for the phase this submission targets —
655	  // server "phase" SSE events override this later, and "done"/setStreaming(false)
656	  // clear it at turn end.
657	  activePhase = inferPhaseFromInput(text, fileText);
658	
659	  // Add typing indicator
660	  const typingEl = appendTypingIndicator();
661	  setStreaming(true);
662	  updateButtonStates();
663	
664	  try {
665	    const body = { sessionId, message: text };
666	    if (fileText) {
667	      body.fileText = fileText;
668	    }
669	
670	    const res = await fetch("/api/chat", {
671	      method: "POST",
672	      headers: { "Content-Type": "application/json" },
673	      body: JSON.stringify(body),
674	    });
675	
676	    if (!res.ok) {
677	      const err = await res.json();
678	      throw new Error(err.error || "Request failed.");
679	    }
680	
681	    // Reuse the typing-indicator bubble as the assistant message. The spinner
682	    // stays visible (inside the same bubble) for the entire SSE stream and is
683	    // removed only when the stream completes.
684	    const assistantEl = typingEl;
685	    const contentEl = assistantEl.querySelector(".message-content");
686	    const textEl = contentEl.querySelector(".streaming-text");
687	    const indicatorEl = contentEl.querySelector(".loading-indicator");
688	    let fullText = "";
689	    let labelSwitchedToWriting = false;
690	
691	    const setLoadingLabel = (msg) => {
692	      const labelEl = indicatorEl.querySelector(".loading-text");
693	      if (labelEl) labelEl.textContent = msg;
694	    };
695	
696	    // Read SSE stream
697	    const reader = res.body.getReader();
698	    const decoder = new TextDecoder();
699	    let buffer = "";
700	
701	    while (true) {
702	      const { done, value } = await reader.read();
703	      if (done) break;
704	
705	      buffer += decoder.decode(value, { stream: true });
706	      const lines = buffer.split("\n");
707	      buffer = lines.pop() || "";
708	
709	      for (const line of lines) {
710	        if (!line.startsWith("data: ")) continue;
711	        const jsonStr = line.slice(6);
712	        if (!jsonStr) continue;
713	
714	        try {
715	          const event = JSON.parse(jsonStr);
716	          if (event.type === "text") {
717	            if (!labelSwitchedToWriting) {
718	              setLoadingLabel("Generating response...");
719	              labelSwitchedToWriting = true;
720	            }
721	            fullText += event.content;
722	            textEl.innerHTML = renderMarkdown(stripInternalMarkers(fullText));
723	            scrollToBottom();
724	          } else if (event.type === "status") {
725	            setLoadingLabel(event.content);
726	            labelSwitchedToWriting = false;
727	          } else if (event.type === "phase") {
728	            activePhase = event.activePhase || null;
729	            if (event.pipelineStep) pipelineStep = event.pipelineStep;
730	            updateButtonStates();
731	          } else if (event.type === "done") {
732	            // Turn ended — clear active-phase spinner and sync pipelineStep
733	            activePhase = null;
734	            if (event.pipelineStep) {
735	              pipelineStep = event.pipelineStep;
736	            }
737	            if (typeof event.awaitingInfo !== "undefined") {
738	              awaitingInfo = event.awaitingInfo;
739	            }
740	            updateButtonStates();
741	            if (event.hasGoalProfile) {
742	              hasGoalProfile = true;
743	            }
744	            // Strip goal profile JSON marker block from rendered content
745	            fullText = stripProfileMarker(fullText);
746	            textEl.innerHTML = renderMarkdown(fullText);
747	            indicatorEl.remove();
748	            hideUploadArea();
749	          } else if (event.type === "error") {
750	            textEl.textContent = event.content;
751	            indicatorEl.remove();
752	            assistantEl.classList.add("error");
753	          }
754	        } catch {
755	          // ignore malformed SSE lines
756	        }
757	      }
758	    }
759	
760	    // Safety net: if the loop exited without a done/error event, ensure the
761	    // spinner is removed so the user isn't left staring at a perpetual spinner.
762	    if (indicatorEl.isConnected) indicatorEl.remove();
763	
764	    if (!fullText && !textEl.textContent) {
765	      textEl.textContent = "No response received. Please try again.";
766	    }
767	  } catch (err) {
768	    typingEl.remove();
769	    appendMessage(
770	      "error",
771	      err.message || "Something went wrong. Please try again."
772	    );
773	  }
774	
775	  setStreaming(false);
776	  scrollToBottom();
777	}
