779	// ── DOM helpers ──────────────────────────────────
780	
781	function appendMessage(role, text) {
782	  const wrapper = document.createElement("div");
783	  wrapper.className = `message ${role}`;
784	
785	  const content = document.createElement("div");
786	  content.className = "message-content";
787	
788	  if (role === "assistant" || role === "error") {
789	    content.innerHTML = text ? renderMarkdown(text) : "";
790	  } else {
791	    content.textContent = text;
792	  }
793	
794	  wrapper.appendChild(content);
795	  messagesContainer.appendChild(wrapper);
