799	
800	function appendTypingIndicator() {
801	  const wrapper = document.createElement("div");
802	  wrapper.className = "message assistant";
803	
804	  const content = document.createElement("div");
805	  content.className = "message-content";
806	  content.innerHTML =
807	    '<div class="streaming-text"></div>' +
808	    '<div class="loading-indicator">' +
809	      '<div class="loading-spinner" aria-hidden="true"></div>' +
810	      '<span class="loading-text">Thinking...</span>' +
811	    '</div>';
812	
813	  wrapper.appendChild(content);
814	  messagesContainer.appendChild(wrapper);
815	  scrollToBottom();
816	  return wrapper;
817	}
818	
819	function setStreaming(val) {
820	  isStreaming = val;
821	  sendBtn.disabled = val;
822	  chatInput.disabled = val;
823	
824	  // During streaming, disable all chips. On finish, restore pipeline-aware states.
825	  if (val) {
826	    quickActions
827	      .querySelectorAll(".action-chip")
828	      .forEach((c) => (c.disabled = true));
829	  } else {
830	    // Safety net — clear spinner if stream ended without a done/phase event
831	    activePhase = null;
832	    updateButtonStates();
833	  }
834	
835	  if (!val) chatInput.focus();
836	}
837	
838	function scrollToBottom() {
839	  messagesContainer.scrollTop = messagesContainer.scrollHeight;
840	}
841	
842	// ── Markdown rendering (lightweight, no deps) ────
843	
844	function renderMarkdown(text) {
845	  let html = escapeHtml(text);
846	
847	  // Code blocks (``` ... ```)
848	  html = html.replace(/```(\w*)\n([\s\S]*?)```/g, (_, lang, code) => {
849	    return `<pre><code>${code.trim()}</code></pre>`;
850	  });
851	
852	  // Inline code
853	  html = html.replace(/`([^`]+)`/g, "<code>$1</code>");
854	
855	  // Bold
856	  html = html.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");
857	
858	  // Italic
859	  html = html.replace(/\*(.+?)\*/g, "<em>$1</em>");
860	
861	  // Headings
862	  html = html.replace(/^### (.+)$/gm, "<h3>$1</h3>");
863	  html = html.replace(/^## (.+)$/gm, "<h2>$1</h2>");
864	  html = html.replace(/^# (.+)$/gm, "<h1>$1</h1>");
865	
866	  // Horizontal rule
867	  html = html.replace(/^---$/gm, "<hr>");
868	
869	  // Unordered lists
870	  html = html.replace(/^(\s*)[-*] (.+)$/gm, "$1<li>$2</li>");
871	
872	  // Ordered lists
873	  html = html.replace(/^(\s*)\d+\. (.+)$/gm, "$1<li>$2</li>");
874	
875	  // Wrap consecutive <li> in <ul>
876	  html = html.replace(/((?:<li>.*<\/li>\n?)+)/g, "<ul>$1</ul>");
877	
878	  // Tables
879	  html = html.replace(
880	    /^(\|.+\|)\n(\|[-| :]+\|)\n((?:\|.+\|\n?)+)/gm,
881	    (_, header, sep, body) => {
882	      const ths = header
883	        .split("|")
884	        .filter((c) => c.trim())
885	        .map((c) => `<th>${c.trim()}</th>`)
886	        .join("");
887	      const rows = body
888	        .trim()
889	        .split("\n")
890	        .map((row) => {
891	          const tds = row
892	            .split("|")
893	            .filter((c) => c.trim())
894	            .map((c) => `<td>${c.trim()}</td>`)
895	            .join("");
896	          return `<tr>${tds}</tr>`;
897	        })
898	        .join("");
899	      return `<table><thead><tr>${ths}</tr></thead><tbody>${rows}</tbody></table>`;
900	    }
901	  );
902	
903	  // Paragraphs — wrap remaining text blocks
904	  html = html
905	    .split("\n\n")
906	    .map((block) => {
907	      block = block.trim();
908	      if (!block) return "";
909	      if (/^<(h[1-3]|ul|ol|pre|table|hr|li|div)/.test(block)) return block;
910	      return `<p>${block.replace(/\n/g, "<br>")}</p>`;
911	    })
912	    .join("\n");
913	
914	  return html;
915	}
916	
917	function escapeHtml(text) {
918	  const div = document.createElement("div");
919	  div.appendChild(document.createTextNode(text));
920	  return div.innerHTML;
921	}
922	
923	// ── Goal profile helpers ────────────────────────
924	
925	const PROFILE_MARKER_RE =
926	  /<!-- GOAL_PROFILE_JSON -->\s*```(?:json)?\s*[\s\S]*?\s*```\s*<!-- \/GOAL_PROFILE_JSON -->/g;
927	
928	// The pipeline-gate skill emits an HTML-comment-wrapped JSON payload. Strip
929	// it on every render so the student never sees the internal state marker.
930	const PIPELINE_GATE_MARKER_RE = /<!-- PIPELINE_GATE[\s\S]*?-->/g;
931	
932	function stripInternalMarkers(text) {
933	  return text
934	    .replace(PROFILE_MARKER_RE, "")
935	    .replace(PIPELINE_GATE_MARKER_RE, "")
936	    .trim();
937	}
938	
939	function stripProfileMarker(text) {
940	  return stripInternalMarkers(text);
941	}
