943	// Download button toggle
944	downloadProfileBtn.addEventListener("click", (e) => {
945	  e.stopPropagation();
946	  downloadDropdown.classList.toggle("download-dropdown--visible");
947	});
948	
949	// Close dropdown when clicking outside
950	document.addEventListener("click", () => {
951	  downloadDropdown.classList.remove("download-dropdown--visible");
952	});
953	
954	// Download format selection
955	downloadDropdown.addEventListener("click", async (e) => {
956	  const btn = e.target.closest(".dropdown-item");
957	  if (!btn || !sessionId) return;
958	
959	  const format = btn.dataset.format;
960	  downloadDropdown.classList.remove("download-dropdown--visible");
961	
962	  try {
963	    const res = await fetch(
964	      `/api/session/${sessionId}/profile?format=${format}`
965	    );
966	    if (!res.ok) {
967	      const err = await res.json();
968	      throw new Error(err.error || "Download failed.");
969	    }
970	
971	    const blob = await res.blob();
972	    const ext = format === "markdown" ? "md" : "json";
973	    const safeName = studentName.replace(/[^a-zA-Z0-9\-_ ]/g, "").replace(/\s+/g, "-");
974	    const url = URL.createObjectURL(blob);
975	    const a = document.createElement("a");
976	    a.href = url;
977	    a.download = `${safeName}-profile.${ext}`;
978	    document.body.appendChild(a);
979	    a.click();
980	    document.body.removeChild(a);
981	    URL.revokeObjectURL(url);
