// ── State ────────────────────────────────────────

let sessionId = null;
let isStreaming = false;
let studentName = "";
let pipelineStep = "ready";
let activePhase = null; // "analyze" | "align" | "build" | null — chip currently pulsing
let awaitingInfo = null; // "analyze" | "align" | "build" | null — pipeline-gate says agent needs info to finish this phase
let pendingFileText = null;
let pendingFileName = null;
let hasGoalProfile = false;

// ── DOM refs ─────────────────────────────────────

const onboardingScreen = document.getElementById("onboarding");
const chatScreen = document.getElementById("chat");
const onboardingForm = document.getElementById("onboarding-form");
const chatForm = document.getElementById("chat-form");
const chatInput = document.getElementById("chat-input");
const sendBtn = document.getElementById("send-btn");
const messagesContainer = document.getElementById("messages");
const newSessionBtn = document.getElementById("new-session-btn");
const quickActions = document.getElementById("quick-actions");
const uploadArea = document.getElementById("upload-area");
const uploadDropzone = document.getElementById("upload-dropzone");
const fileUpload = document.getElementById("file-upload");
const btnBrowse = document.getElementById("btn-browse");
const profileDownload = document.getElementById("profile-download");
const downloadProfileBtn = document.getElementById("download-profile-btn");
const downloadDropdown = document.getElementById("download-dropdown");
const uploadProfileLink = document.getElementById("upload-profile-link");
const profileFileInput = document.getElementById("profile-file-input");

// ── Pipeline step helpers ────────────────────────

const STEPS = ["ready", "analyzed", "aligned", "proposed"];

function stepIndex(step) {
  return STEPS.indexOf(step);
}

function inferPhaseFromInput(message, fileText) {
  if (fileText) return "analyze";

  const analyzeBtn = quickActions.querySelector('[data-step="analyze"]');
  const alignBtn = quickActions.querySelector('[data-step="align"]');
  const buildBtn = quickActions.querySelector('[data-step="build"]');
  if (message === analyzeBtn.dataset.prompt) return "analyze";
  if (message === alignBtn.dataset.prompt) return "align";
  if (message === buildBtn.dataset.prompt) return "build";

  const idx = stepIndex(pipelineStep);
  if (idx === 0) return "analyze";
  if (idx === 1) return "align";
  if (idx === 2) return "build";
  return null;
}

function updateButtonStates() {
  const analyzeBtn = quickActions.querySelector('[data-step="analyze"]');
  const alignBtn = quickActions.querySelector('[data-step="align"]');
  const buildBtn = quickActions.querySelector('[data-step="build"]');
  const connector1 = document.getElementById("connector-1");
  const connector2 = document.getElementById("connector-2");
  const idx = stepIndex(pipelineStep);

  // Reset all
  [analyzeBtn, alignBtn, buildBtn].forEach((btn) => {
    btn.classList.remove(
      "action-chip--completed",
      "action-chip--current",
      "action-chip--locked",
      "action-chip--working"
    );
    btn.disabled = false;
    btn.title = "";
  });
  connector1.classList.remove(
    "step-connector--completed",
    "step-connector--partial"
  );
  connector2.classList.remove(
    "step-connector--completed",
    "step-connector--partial"
  );

  // Analyze button
  if (idx >= 1) {
    analyzeBtn.classList.add("action-chip--completed");
    analyzeBtn.disabled = true;
    analyzeBtn.title = "Assignment analysis complete";
    analyzeBtn.querySelector(".step-indicator").textContent = "\u2713";
  } else {
    analyzeBtn.classList.add("action-chip--current");
    analyzeBtn.querySelector(".step-indicator").textContent = "1";
  }

  // Connector 1
  if (idx >= 1) {
    connector1.classList.add("step-connector--completed");
  }

  // Align button
  if (idx >= 2) {
    alignBtn.classList.add("action-chip--completed");
    alignBtn.disabled = true;
    alignBtn.title = "Career alignment complete";
    alignBtn.querySelector(".step-indicator").textContent = "\u2713";
  } else if (idx >= 1) {
    alignBtn.classList.add("action-chip--current");
    alignBtn.querySelector(".step-indicator").textContent = "2";
  } else {
    alignBtn.classList.add("action-chip--locked");
    alignBtn.disabled = true;
    alignBtn.title = "Complete assignment analysis first";
    alignBtn.querySelector(".step-indicator").textContent = "2";
  }

  // Connector 2
  if (idx >= 2) {
    connector2.classList.add("step-connector--completed");
  }

  // Awaiting-info halfway marker — only paints on the connector AFTER the
  // phase-in-progress chip, and never replaces an already-completed connector.
  if (awaitingInfo === "analyze" && idx < 1) {
    connector1.classList.add("step-connector--partial");
  } else if (awaitingInfo === "align" && idx < 2) {
    connector2.classList.add("step-connector--partial");
  }
  // awaitingInfo === "build": no connector after chip 3, so the chip stays
  // --current. (Visible build-awaiting UX is deliberately out of scope.)

  // Build button
  if (idx >= 3) {
    buildBtn.classList.add("action-chip--completed");
    buildBtn.disabled = true;
    buildBtn.title = "Proposal built";
    buildBtn.querySelector(".step-indicator").textContent = "\u2713";
  } else if (idx >= 2) {
    buildBtn.classList.add("action-chip--current");
    buildBtn.querySelector(".step-indicator").textContent = "3";
  } else {
    buildBtn.classList.add("action-chip--locked");
    buildBtn.disabled = true;
    buildBtn.title =
      idx < 1
        ? "Complete analysis and alignment first"
        : "Complete career alignment first";
    buildBtn.querySelector(".step-indicator").textContent = "3";
  }

  // Working overlay — active phase pulses with a spinner in its step indicator.
  // Takes visual priority over completed/current/locked via CSS source order.
  if (activePhase) {
    const activeBtn = quickActions.querySelector(
      `[data-step="${activePhase}"]`
    );
    if (activeBtn) {
      activeBtn.classList.add("action-chip--working");
      const indicator = activeBtn.querySelector(".step-indicator");
      indicator.textContent = "";
      const spinner = document.createElement("span");
      spinner.className = "chip-spinner";
      spinner.setAttribute("aria-hidden", "true");
      indicator.appendChild(spinner);
    }
  }

  // Preserve streaming-lock: chips stay disabled until the turn ends.
  if (isStreaming) {
    [analyzeBtn, alignBtn, buildBtn].forEach((btn) => (btn.disabled = true));
  }
}

// ── Onboarding ───────────────────────────────────

const careerChipGrid = document.getElementById("career-chips");
careerChipGrid.addEventListener("click", (e) => {
  const chip = e.target.closest(".chip-option");
  if (!chip) return;
  const selected = chip.classList.toggle("chip-option--selected");
  chip.setAttribute("aria-pressed", String(selected));
});

onboardingForm.addEventListener("submit", async (e) => {
  e.preventDefault();

  const selectedChips = [...careerChipGrid.querySelectorAll(".chip-option--selected")]
    .map((c) => c.dataset.value);
  if (selectedChips.length === 0) {
    alert("Pick at least one career area that sounds interesting.");
    return;
  }

  const details = document.getElementById("careerDetails").value.trim();
  const careerGoals = details
    ? `${selectedChips.join(", ")}. More specifically: ${details}`
    : selectedChips.join(", ");

  const data = {
    name: document.getElementById("name").value,
    major: document.getElementById("major").value,
    year: document.getElementById("year").value,
    course: document.getElementById("course").value,
    careerGoals,
  };
  studentName = data.name;

  const btn = onboardingForm.querySelector("button[type=submit]");
  btn.disabled = true;
  btn.textContent = "Setting up...";

  try {
    const res = await fetch("/api/session", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(data),
    });

    if (!res.ok) {
      const err = await res.json();
      throw new Error(err.error || "Failed to create session.");
    }

    const result = await res.json();
    sessionId = result.sessionId;
    pipelineStep = result.pipelineStep || "ready";
    enterChatScreen({ returning: false });
  } catch (err) {
    alert(err.message);
    btn.disabled = false;
    btn.textContent = "Get Started";
  }
});

// Shared transition used by both the intro-survey path and the profile-upload
// path. Assumes sessionId, studentName, and pipelineStep have been set.
function enterChatScreen({ returning }) {
  // Re-query by ID because the "New session" handler replaces #welcome-message
  // via messagesContainer.innerHTML, leaving any earlier-captured reference
  // pointing at a detached node.
  const welcomeEl = document.getElementById("welcome-message");
  const intro = returning
    ? `Welcome back, ${studentName}! I loaded your saved profile. We can pick up wherever you left off — share the assignment you're working on, or click **Analyze Assignment** above to start a new one.`
    : `Hi ${studentName}! I'm **AssignmentAlly**. I help you build augmented, career-connected versions of your assignments and draft formal proposals you can present to your professor.\n\n` +
      `Here's how we'll work together:\n\n` +
      `1. **Analyze** your assignment to understand what it requires\n` +
      `2. **Align** it with your career goals to find augmentation opportunities\n` +
      `3. **Build** a formal proposal with rubric compliance proof\n\n` +
      `Start by clicking **Analyze Assignment** above to upload your syllabus or assignment, or just describe it in the chat box.`;
  welcomeEl.innerHTML = renderMarkdown(intro);

  onboardingScreen.classList.remove("active");
  chatScreen.classList.add("active");
  updateButtonStates();
  chatInput.focus();
}

// ── Profile upload (skip the intro survey) ──────────────────────────

uploadProfileLink.addEventListener("click", () => profileFileInput.click());

profileFileInput.addEventListener("change", async (e) => {
  const file = e.target.files?.[0];
  if (!file) return;

  try {
    const text = await file.text();
    let payload;
    try {
      payload = JSON.parse(text);
    } catch {
      throw new Error("That file isn't valid JSON. Please upload a profile exported from AssignmentAlly.");
    }

    const res = await fetch("/api/session/import", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.error || "Couldn't use this profile file.");
    }

    const result = await res.json();
    sessionId = result.sessionId;
    pipelineStep = result.pipelineStep || "ready";
    studentName = payload.student?.name || "";
    hasGoalProfile = !!result.hasGoalProfile;
    enterChatScreen({ returning: true });
  } catch (err) {
    alert(err.message);
  } finally {
    // Clear so picking the same file again re-fires 'change'.
    profileFileInput.value = "";
  }
});

// ── Examples page ────────────────────────────────

const examplesScreen = document.getElementById("examples");
const viewExamplesBtn = document.getElementById("view-examples-btn");
const examplesBackBtn = document.getElementById("examples-back-btn");
const examplesListBtn = document.getElementById("examples-list-btn");
const examplesGrid = document.getElementById("examples-grid");
const exampleTitleEl = document.getElementById("example-title");
const exampleScenarioEl = document.getElementById("example-scenario");
const exampleTurnsEl = document.getElementById("example-turns");

let examplesLoaded = false;

viewExamplesBtn.addEventListener("click", async () => {
  onboardingScreen.classList.remove("active");
  examplesScreen.classList.remove("detail-view");
  examplesScreen.classList.add("active");

  if (examplesLoaded) return;

  try {
    const res = await fetch("/api/examples");
    if (!res.ok) throw new Error("Failed to load examples.");
    const items = await res.json();
    renderExamplesList(items);
    examplesLoaded = true;
  } catch (err) {
    examplesGrid.innerHTML = `<p class="examples-error">${err.message}</p>`;
  }
});

function renderExamplesList(items) {
  examplesGrid.innerHTML = "";
  for (const item of items) {
    const card = document.createElement("button");
    card.type = "button";
    card.className = "example-card";
    card.dataset.id = item.id;

    const title = document.createElement("h3");
    title.className = "example-card-title";
    title.textContent = item.title || item.id;

    const scenario = document.createElement("p");
    scenario.className = "example-card-scenario";
    scenario.textContent = item.scenario || "";

    const link = document.createElement("span");
    link.className = "example-card-link";
    link.textContent = "Read full example →";

    card.appendChild(title);
    if (item.scenario) card.appendChild(scenario);
    card.appendChild(link);
    examplesGrid.appendChild(card);
  }
}

examplesGrid.addEventListener("click", async (e) => {
  const card = e.target.closest(".example-card");
  if (!card) return;
  await openExample(card.dataset.id);
});

async function openExample(id) {
  exampleTitleEl.textContent = "";
  exampleScenarioEl.textContent = "";
  exampleTurnsEl.innerHTML = '<p class="examples-loading">Loading...</p>';
  examplesScreen.classList.add("detail-view");
  const body = examplesScreen.querySelector(".examples-body");
  if (body) body.scrollTop = 0;

  try {
    const res = await fetch(`/api/examples/${encodeURIComponent(id)}`);
    if (!res.ok) throw new Error("Failed to load example.");
    const data = await res.json();
    exampleTitleEl.textContent = data.title || "";
    exampleScenarioEl.textContent = data.scenario || "";
    renderExampleTurns(data.turns || []);
  } catch (err) {
    exampleTurnsEl.innerHTML = `<p class="examples-error">${err.message}</p>`;
  }
}

function renderExampleTurns(turns) {
  exampleTurnsEl.innerHTML = "";
  if (!turns.length) {
    exampleTurnsEl.innerHTML =
      '<p class="examples-error">No conversation content to display.</p>';
    return;
  }
  for (const turn of turns) {
    const wrapper = document.createElement("div");
    wrapper.className = `message ${turn.role === "user" ? "user" : "assistant"}`;

    const content = document.createElement("div");
    content.className = "message-content";
    if (turn.role === "assistant") {
      content.innerHTML = renderMarkdown(turn.content);
    } else {
      content.textContent = turn.content;
    }

    wrapper.appendChild(content);
    exampleTurnsEl.appendChild(wrapper);
  }
}

examplesBackBtn.addEventListener("click", () => {
  examplesScreen.classList.remove("active");
  examplesScreen.classList.remove("detail-view");
  onboardingScreen.classList.add("active");
});

examplesListBtn.addEventListener("click", () => {
  examplesScreen.classList.remove("detail-view");
});

// ── Chat ─────────────────────────────────────────

chatForm.addEventListener("submit", (e) => {
  e.preventDefault();
  sendMessage();
});

chatInput.addEventListener("keydown", (e) => {
  if (e.key === "Enter" && !e.shiftKey) {
    e.preventDefault();
    sendMessage();
  }
});

// Auto-resize textarea
chatInput.addEventListener("input", () => {
  chatInput.style.height = "auto";
  chatInput.style.height = Math.min(chatInput.scrollHeight, 140) + "px";
});

// Quick action chips
quickActions.addEventListener("click", (e) => {
  const chip = e.target.closest(".action-chip");
  if (!chip || isStreaming || chip.disabled) return;

  const step = chip.dataset.step;

  if (step === "analyze") {
    // Toggle upload area visibility
    toggleUploadArea();
    return;
  }

  // For align and build, load the prompt into the text field so the user can
  // review or edit it before sending.
  chatInput.value = chip.dataset.prompt;
  chatInput.focus();
  chatInput.setSelectionRange(chatInput.value.length, chatInput.value.length);
  chatInput.dispatchEvent(new Event("input"));
});

// New session
function showToast(message, variant = "default", durationMs = 3500) {
  const container = document.getElementById("toast-container");
  if (!container) return;
  const toast = document.createElement("div");
  toast.className =
    "toast" + (variant !== "default" ? ` toast--${variant}` : "");
  toast.setAttribute("role", variant === "error" ? "alert" : "status");
  toast.textContent = message;
  container.appendChild(toast);
  setTimeout(() => {
    toast.classList.add("toast--dismiss");
    toast.addEventListener("animationend", () => toast.remove(), { once: true });
  }, durationMs);
}

newSessionBtn.addEventListener("click", () => {
  if (isStreaming) {
    showToast(
      "Please wait — the agent is still responding. You can start a new session once it finishes.",
      "warn"
    );
    return;
  }
  if (
    sessionId &&
    !confirm(
      "Start a new session? Your current conversation will be cleared."
    )
  ) {
    return;
  }
  sessionId = null;
  isStreaming = false;
  studentName = "";
  pipelineStep = "ready";
  activePhase = null;
  awaitingInfo = null;
  pendingFileText = null;
  pendingFileName = null;
  hasGoalProfile = false;
  downloadDropdown.classList.remove("download-dropdown--visible");
  hideUploadArea();
  onboardingForm.reset();
  messagesContainer.innerHTML =
    '<div class="message assistant"><div class="message-content" id="welcome-message"></div></div>';
  chatScreen.classList.remove("active");
  onboardingScreen.classList.add("active");
  const btn = onboardingForm.querySelector("button[type=submit]");
  btn.disabled = false;
  btn.textContent = "Get Started";
  updateButtonStates();
});

// ── Upload area ──────────────────────────────────

function toggleUploadArea() {
  if (uploadArea.classList.contains("upload-area--visible")) {
    hideUploadArea();
  } else {
    showUploadArea();
  }
}

function showUploadArea() {
  uploadArea.classList.add("upload-area--visible");
}

function hideUploadArea() {
  uploadArea.classList.remove("upload-area--visible");
}

btnBrowse.addEventListener("click", () => {
  fileUpload.click();
});

fileUpload.addEventListener("change", async () => {
  const file = fileUpload.files[0];
  if (!file) return;

  // Show uploading state
  const originalTitle = uploadDropzone.querySelector(".upload-title");
  const originalText = originalTitle.textContent;
  originalTitle.textContent = `Uploading ${file.name}...`;
  btnBrowse.disabled = true;

  try {
    const formData = new FormData();
    formData.append("file", file);

    const res = await fetch("/api/upload", {
      method: "POST",
      body: formData,
    });

    const result = await res.json();

    if (!res.ok) {
      throw new Error(result.error || "Upload failed.");
    }

    // Store file text and send the analyze prompt
    pendingFileText = result.text;
    pendingFileName = result.fileName;
    hideUploadArea();

    const analyzeBtn = quickActions.querySelector('[data-step="analyze"]');
    chatInput.value = analyzeBtn.dataset.prompt;
    sendMessage();
  } catch (err) {
    alert(err.message);
    originalTitle.textContent = originalText;
  }

  btnBrowse.disabled = false;
  fileUpload.value = "";
});

// Drag and drop
uploadDropzone.addEventListener("dragover", (e) => {
  e.preventDefault();
  uploadDropzone.classList.add("drag-over");
});

uploadDropzone.addEventListener("dragleave", () => {
  uploadDropzone.classList.remove("drag-over");
});

uploadDropzone.addEventListener("drop", async (e) => {
  e.preventDefault();
  uploadDropzone.classList.remove("drag-over");

  const file = e.dataTransfer.files[0];
  if (!file) return;

  const ext = file.name.split(".").pop().toLowerCase();
  if (!["pdf", "txt", "md"].includes(ext)) {
    alert(
      `Unsupported file type ".${ext}". Please use PDF, TXT, or MD files.`
    );
    return;
  }

  // Upload the dropped file
  const originalTitle = uploadDropzone.querySelector(".upload-title");
  const originalText = originalTitle.textContent;
  originalTitle.textContent = `Uploading ${file.name}...`;

  try {
    const formData = new FormData();
    formData.append("file", file);

    const res = await fetch("/api/upload", {
      method: "POST",
      body: formData,
    });

    const result = await res.json();

    if (!res.ok) {
      throw new Error(result.error || "Upload failed.");
    }

    pendingFileText = result.text;
    pendingFileName = result.fileName;
    hideUploadArea();

    const analyzeBtn = quickActions.querySelector('[data-step="analyze"]');
    chatInput.value = analyzeBtn.dataset.prompt;
    sendMessage();
  } catch (err) {
    alert(err.message);
    originalTitle.textContent = originalText;
  }
});

// ── Send message ─────────────────────────────────

async function sendMessage() {
  const text = chatInput.value.trim();
  if (!text || isStreaming || !sessionId) return;

  // Capture and clear pending file info
  const fileText = pendingFileText;
  const fileName = pendingFileName;
  pendingFileText = null;
  pendingFileName = null;

  // Add user message — include file name if uploaded
  const displayText = fileName ? `[Uploaded: ${fileName}]\n${text}` : text;
  appendMessage("user", displayText);
  chatInput.value = "";
  chatInput.style.height = "auto";

  // Optimistically highlight the chip for the phase this submission targets —
  // server "phase" SSE events override this later, and "done"/setStreaming(false)
  // clear it at turn end.
  activePhase = inferPhaseFromInput(text, fileText);

  // Add typing indicator
  const typingEl = appendTypingIndicator();
  setStreaming(true);
  updateButtonStates();

  try {
    const body = { sessionId, message: text };
    if (fileText) {
      body.fileText = fileText;
    }

    const res = await fetch("/api/chat", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });

    if (!res.ok) {
      const err = await res.json();
      throw new Error(err.error || "Request failed.");
    }

    // Reuse the typing-indicator bubble as the assistant message. The spinner
    // stays visible (inside the same bubble) for the entire SSE stream and is
    // removed only when the stream completes.
    const assistantEl = typingEl;
    const contentEl = assistantEl.querySelector(".message-content");
    const textEl = contentEl.querySelector(".streaming-text");
    const indicatorEl = contentEl.querySelector(".loading-indicator");
    let fullText = "";
    let labelSwitchedToWriting = false;

    const setLoadingLabel = (msg) => {
      const labelEl = indicatorEl.querySelector(".loading-text");
      if (labelEl) labelEl.textContent = msg;
    };

    // Read SSE stream
    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "";

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split("\n");
      buffer = lines.pop() || "";

      for (const line of lines) {
        if (!line.startsWith("data: ")) continue;
        const jsonStr = line.slice(6);
        if (!jsonStr) continue;

        try {
          const event = JSON.parse(jsonStr);
          if (event.type === "text") {
            if (!labelSwitchedToWriting) {
              setLoadingLabel("Generating response...");
              labelSwitchedToWriting = true;
            }
            fullText += event.content;
            textEl.innerHTML = renderMarkdown(stripInternalMarkers(fullText));
            scrollToBottom();
          } else if (event.type === "status") {
            setLoadingLabel(event.content);
            labelSwitchedToWriting = false;
          } else if (event.type === "phase") {
            activePhase = event.activePhase || null;
            if (event.pipelineStep) pipelineStep = event.pipelineStep;
            updateButtonStates();
          } else if (event.type === "done") {
            // Turn ended — clear active-phase spinner and sync pipelineStep
            activePhase = null;
            if (event.pipelineStep) {
              pipelineStep = event.pipelineStep;
            }
            if (typeof event.awaitingInfo !== "undefined") {
              awaitingInfo = event.awaitingInfo;
            }
            updateButtonStates();
            if (event.hasGoalProfile) {
              hasGoalProfile = true;
            }
            // Strip goal profile JSON marker block from rendered content
            fullText = stripProfileMarker(fullText);
            textEl.innerHTML = renderMarkdown(fullText);
            indicatorEl.remove();
            hideUploadArea();
          } else if (event.type === "error") {
            textEl.textContent = event.content;
            indicatorEl.remove();
            assistantEl.classList.add("error");
          }
        } catch {
          // ignore malformed SSE lines
        }
      }
    }

    // Safety net: if the loop exited without a done/error event, ensure the
    // spinner is removed so the user isn't left staring at a perpetual spinner.
    if (indicatorEl.isConnected) indicatorEl.remove();

    if (!fullText && !textEl.textContent) {
      textEl.textContent = "No response received. Please try again.";
    }
  } catch (err) {
    typingEl.remove();
    appendMessage(
      "error",
      err.message || "Something went wrong. Please try again."
    );
  }

  setStreaming(false);
  scrollToBottom();
}

// ── DOM helpers ──────────────────────────────────

function appendMessage(role, text) {
  const wrapper = document.createElement("div");
  wrapper.className = `message ${role}`;

  const content = document.createElement("div");
  content.className = "message-content";

  if (role === "assistant" || role === "error") {
    content.innerHTML = text ? renderMarkdown(text) : "";
  } else {
    content.textContent = text;
  }

  wrapper.appendChild(content);
  messagesContainer.appendChild(wrapper);
  scrollToBottom();
  return wrapper;
}

function appendTypingIndicator() {
  const wrapper = document.createElement("div");
  wrapper.className = "message assistant";

  const content = document.createElement("div");
  content.className = "message-content";
  content.innerHTML =
    '<div class="streaming-text"></div>' +
    '<div class="loading-indicator">' +
      '<div class="loading-spinner" aria-hidden="true"></div>' +
      '<span class="loading-text">Thinking...</span>' +
    '</div>';

  wrapper.appendChild(content);
  messagesContainer.appendChild(wrapper);
  scrollToBottom();
  return wrapper;
}

function setStreaming(val) {
  isStreaming = val;
  sendBtn.disabled = val;
  chatInput.disabled = val;

  // During streaming, disable all chips. On finish, restore pipeline-aware states.
  if (val) {
    quickActions
      .querySelectorAll(".action-chip")
      .forEach((c) => (c.disabled = true));
  } else {
    // Safety net — clear spinner if stream ended without a done/phase event
    activePhase = null;
    updateButtonStates();
  }

  if (!val) chatInput.focus();
}

function scrollToBottom() {
  messagesContainer.scrollTop = messagesContainer.scrollHeight;
}

// ── Markdown rendering (lightweight, no deps) ────

function renderMarkdown(text) {
  let html = escapeHtml(text);

  // Code blocks (``` ... ```)
  html = html.replace(/```(\w*)\n([\s\S]*?)```/g, (_, lang, code) => {
    return `<pre><code>${code.trim()}</code></pre>`;
  });

  // Inline code
  html = html.replace(/`([^`]+)`/g, "<code>$1</code>");

  // Bold
  html = html.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");

  // Italic
  html = html.replace(/\*(.+?)\*/g, "<em>$1</em>");

  // Headings
  html = html.replace(/^### (.+)$/gm, "<h3>$1</h3>");
  html = html.replace(/^## (.+)$/gm, "<h2>$1</h2>");
  html = html.replace(/^# (.+)$/gm, "<h1>$1</h1>");

  // Horizontal rule
  html = html.replace(/^---$/gm, "<hr>");

  // Unordered lists
  html = html.replace(/^(\s*)[-*] (.+)$/gm, "$1<li>$2</li>");

  // Ordered lists
  html = html.replace(/^(\s*)\d+\. (.+)$/gm, "$1<li>$2</li>");

  // Wrap consecutive <li> in <ul>
  html = html.replace(/((?:<li>.*<\/li>\n?)+)/g, "<ul>$1</ul>");

  // Tables
  html = html.replace(
    /^(\|.+\|)\n(\|[-| :]+\|)\n((?:\|.+\|\n?)+)/gm,
    (_, header, sep, body) => {
      const ths = header
        .split("|")
        .filter((c) => c.trim())
        .map((c) => `<th>${c.trim()}</th>`)
        .join("");
      const rows = body
        .trim()
        .split("\n")
        .map((row) => {
          const tds = row
            .split("|")
            .filter((c) => c.trim())
            .map((c) => `<td>${c.trim()}</td>`)
            .join("");
          return `<tr>${tds}</tr>`;
        })
        .join("");
      return `<table><thead><tr>${ths}</tr></thead><tbody>${rows}</tbody></table>`;
    }
  );

  // Paragraphs — wrap remaining text blocks
  html = html
    .split("\n\n")
    .map((block) => {
      block = block.trim();
      if (!block) return "";
      if (/^<(h[1-3]|ul|ol|pre|table|hr|li|div)/.test(block)) return block;
      return `<p>${block.replace(/\n/g, "<br>")}</p>`;
    })
    .join("\n");

  return html;
}

function escapeHtml(text) {
  const div = document.createElement("div");
  div.appendChild(document.createTextNode(text));
  return div.innerHTML;
}

// ── Goal profile helpers ────────────────────────

const PROFILE_MARKER_RE =
  /<!-- GOAL_PROFILE_JSON -->\s*```(?:json)?\s*[\s\S]*?\s*```\s*<!-- \/GOAL_PROFILE_JSON -->/g;

// The pipeline-gate skill emits an HTML-comment-wrapped JSON payload. Strip
// it on every render so the student never sees the internal state marker.
const PIPELINE_GATE_MARKER_RE = /<!-- PIPELINE_GATE[\s\S]*?-->/g;

function stripInternalMarkers(text) {
  return text
    .replace(PROFILE_MARKER_RE, "")
    .replace(PIPELINE_GATE_MARKER_RE, "")
    .trim();
}

function stripProfileMarker(text) {
  return stripInternalMarkers(text);
}

// Download button toggle
downloadProfileBtn.addEventListener("click", (e) => {
  e.stopPropagation();
  downloadDropdown.classList.toggle("download-dropdown--visible");
});

// Close dropdown when clicking outside
document.addEventListener("click", () => {
  downloadDropdown.classList.remove("download-dropdown--visible");
});

// Download format selection
downloadDropdown.addEventListener("click", async (e) => {
  const btn = e.target.closest(".dropdown-item");
  if (!btn || !sessionId) return;

  const format = btn.dataset.format;
  downloadDropdown.classList.remove("download-dropdown--visible");

  try {
    const res = await fetch(
      `/api/session/${sessionId}/profile?format=${format}`
    );
    if (!res.ok) {
      const err = await res.json();
      throw new Error(err.error || "Download failed.");
    }

    const blob = await res.blob();
    const ext = format === "markdown" ? "md" : "json";
    const safeName = studentName.replace(/[^a-zA-Z0-9\-_ ]/g, "").replace(/\s+/g, "-");
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${safeName}-profile.${ext}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  } catch (err) {
    alert(err.message);
  }
});

