const sample = `Here is your proposal...

<!-- PROPOSAL_METRICS
{"assignmentAlignment":{"score":95,"reason":"All six rubric criteria addressed; depth added without removing requirements."},"goalAlignment":{"score":82,"reason":"Strong fit with primary career goal (Controls Engineer); secondary goal less directly served."},"professorAcceptance":{"concerns":[{"severity":"low","issue":"Augmented timeline is tight against the original two-week window — recommend a midpoint check-in."},{"severity":"medium","issue":"PLC simulator dependency may need IT approval; frame as a request rather than a fait accompli."}]}}
-->

<!-- PIPELINE_GATE {"phase":"build","canAdvance":true,"reason":"Proposal complete."} -->`;

const PROPOSAL_METRICS_RE = /<!-- PROPOSAL_METRICS\s*([\s\S]*?)\s*-->/g;
const m = [...sample.matchAll(PROPOSAL_METRICS_RE)];
console.log("matches:", m.length);
const parsed = JSON.parse(m[m.length - 1][1]);
console.log("aa score:", parsed.assignmentAlignment.score);
console.log("ga reason:", parsed.goalAlignment.reason.slice(0, 50));
console.log("concerns count:", parsed.professorAcceptance.concerns.length);
console.log("concern[0].severity:", parsed.professorAcceptance.concerns[0].severity);

// Verify strip of both markers leaves the prose
const stripped = sample
  .replace(/<!-- PIPELINE_GATE[\s\S]*?-->/g, "")
  .replace(/<!-- PROPOSAL_METRICS[\s\S]*?-->/g, "")
  .trim();
console.log("stripped:", JSON.stringify(stripped));
'
